jQuery.fn.makePositioned=function(t,e){var o,s,r,i,a,h,n,p=this.eq(0);switch(o=e.offset(),s=e.outerHeight(),r=e.outerWidth(),i=o.left,a=o.top,h=p.outerHeight(),n=p.outerWidth(),t){case"bottom":a+=s;break;case"right":i+=r;break;case"left":i-=n;break;case"top":a-=h}return p.css({top:parseInt(a)+"px",left:parseInt(i)+"px",position:"absolute"}),this};